  ('elementary-10ced7e2-moex-00382', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '刑法第15條第1項規定：「對於犯罪結果之發生，法律上有防止之義務，能防止而不防止者，與因積極 行為發生結果者同」。此乃關於何種犯罪之規定？', '["過失犯", "不純正不作為犯", "純正不作為犯", "想像競合犯"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:45+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00383', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '甲對於警察機關委託之拖吊業者不滿，當拖吊業者在交通頻繁之處所執行拖吊勤務時，對拖吊業者比中指 侮辱之。甲之行為如何評價？', '["無罪", "公然侮辱罪", "侮辱公務員罪", "妨害秩序罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:45+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00384', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '下列關於加重結果犯之敘述，何者錯誤？', '["刑法第17條之加重結果犯，以能預見加重結果之發生為要件", "刑法第17條之加重結果犯係故意的基本犯罪與過失加重結果之結合犯罪", "不論法有無明文規定，客觀上可能預見加重結果，即足以構成加重結果犯", "就加重結果之發生，具有主觀過失，方能構成"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:45+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00385', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '公務員甲因需錢孔急，乃與非公務員之友人乙商量，由乙侵占其所任職公司業務上所管領之現金新臺幣 5百萬元得逞，供2人平分花用，依實務見解下列敘述何者正確？', '["甲成立普通侵占罪", "甲成立公務侵占罪", "甲與乙成立業務侵占罪之共同正犯", "甲成立業務侵占罪之事後幫助犯"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:45+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00386', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '關於故意與過失，下列敘述何者正確？', '["行為人對於構成犯罪之事實，雖預見其能發生而確信其不發生者，以故意論", "行為人對於構成犯罪之事實，預見其發生而其發生並不違背其本意者，以過失論", "故意可分為有認識之故意與無認識之故意", "故意可分為直接故意與間接故意"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:45+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00387', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '下列何者，非屬刑法上之公務員？', '["臺大醫院的志工", "直轄市市長", "法警", "書記官"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:45+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
